import{_ as t,o as n,c as a,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Introductie","description":"","frontmatter":{},"headers":[],"relativePath":"nl/getting-started/introduction.md","filePath":"nl/getting-started/introduction.md"}'),i={name:"nl/getting-started/introduction.md"};function d(o,e,l,s,u,g){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="introductie" tabindex="-1">Introductie <a class="header-anchor" href="#introductie" aria-label="Permalink to &quot;Introductie&quot;">​</a></h1><p>MyCompanyDesk is een alles-in-een boekhoud- en bedrijfsmanagementplatform, ontworpen voor zzp&#39;ers, kleine bedrijven en vastgoedbeheerders. Het helpt je bij het beheren van je volledige financiele workflow — van het maken van facturen en het bijhouden van uitgaven tot het doen van BTW-aangifte en het beheren van klantrelaties.</p><h2 id="wat-kun-je-doen-met-mycompanydesk" tabindex="-1">Wat kun je doen met MyCompanyDesk? <a class="header-anchor" href="#wat-kun-je-doen-met-mycompanydesk" aria-label="Permalink to &quot;Wat kun je doen met MyCompanyDesk?&quot;">​</a></h2><ul><li><strong>Facturen maken en versturen</strong> — Professionele facturen met betaallinks, PDF-generatie en e-mailverzending</li><li><strong>Uitgaven bijhouden</strong> — Registreer uitgaven handmatig of scan bonnen met AI-gestuurde OCR</li><li><strong>Klanten beheren</strong> — Onderhoud een complete klantendatabase met contactgegevens en geschiedenis</li><li><strong>Offertes maken</strong> — Maak offertes en zet ze om naar facturen wanneer ze geaccepteerd zijn</li><li><strong>Projecten beheren</strong> — Organiseer werk in projecten, registreer tijd en monitor winstgevendheid</li><li><strong>Contracten beheren</strong> — Stel terugkerende service- of huurcontracten in</li><li><strong>Objecten bijhouden</strong> — Beheer huurwoningen, voertuigen en apparatuur</li><li><strong>Facturatie automatiseren</strong> — Stel terugkerende facturen en uitgaven in</li><li><strong>Rapportages bekijken</strong> — Omzet, winst, cashflow, BTW en klantanalyses</li><li><strong>Samenwerken</strong> — Nodig teamleden uit, stel rechten in en deel met je boekhouder</li></ul><h2 id="ondersteunde-talen" tabindex="-1">Ondersteunde talen <a class="header-anchor" href="#ondersteunde-talen" aria-label="Permalink to &quot;Ondersteunde talen&quot;">​</a></h2><p>MyCompanyDesk is volledig beschikbaar in:</p><ul><li>English</li><li>Nederlands (Dutch)</li><li>Deutsch (German)</li><li>Français (French)</li></ul><p>Je kunt op elk moment van taal wisselen via je profielinstellingen. Facturen en e-mails kunnen in elk van deze talen worden verstuurd, ongeacht je interfacetaal.</p><h2 id="abonnementen" tabindex="-1">Abonnementen <a class="header-anchor" href="#abonnementen" aria-label="Permalink to &quot;Abonnementen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Functie</th><th>Gratis</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Facturen &amp; offertes</td><td>Beperkt</td><td>Onbeperkt</td><td>Onbeperkt</td></tr><tr><td>Klanten</td><td>Beperkt</td><td>Onbeperkt</td><td>Onbeperkt</td></tr><tr><td>Uitgaven bijhouden</td><td>Basis</td><td>Volledig</td><td>Volledig</td></tr><tr><td>Bonnen scannen</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>AI-suggesties</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Eigen huisstijl</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Teamleden</td><td>1</td><td>Tot 5</td><td>Onbeperkt</td></tr><tr><td>Rapportages &amp; export</td><td>Basis</td><td>Volledig</td><td>Volledig</td></tr><tr><td>API-toegang</td><td>-</td><td>-</td><td>Ja</td></tr></tbody></table><h2 id="hulp-krijgen" tabindex="-1">Hulp krijgen <a class="header-anchor" href="#hulp-krijgen" aria-label="Permalink to &quot;Hulp krijgen&quot;">​</a></h2><ul><li>Gebruik de <strong>contextuele gids</strong> (het hulp-icoon in de app) voor contextgerichte assistentie</li><li>Blader door deze documentatie voor gedetailleerde functiegidsen</li><li>Neem contact op met support via het in-app supportticketsysteem</li></ul><h2 id="volgende-stappen" tabindex="-1">Volgende stappen <a class="header-anchor" href="#volgende-stappen" aria-label="Permalink to &quot;Volgende stappen&quot;">​</a></h2><p>Klaar om te beginnen? Ga naar <a href="/nl/getting-started/create-account">Account aanmaken</a> om je werkruimte in te richten.</p>',14)])])}const p=t(i,[["render",d]]);export{h as __pageData,p as default};
